  const badge = document.createElement('span');
  badge.className = 'ticker-badge';
  badge.dataset.ticker = 'AAPL';
  badge.textContent = 'AAPL';

  // Temporarily add it and click it
  const firstRow = newsBody.querySelector('tr');
  if (firstRow) {
    const firstCell = firstRow.querySelector('td');
    if (firstCell) {
      firstCell.appendChild(badge);
      badge.click();
      // remove after click
      setTimeout(() => badge.remove(), 100);
      return 'clicked fake AAPL badge';
    }
  }
  return 'could not find row to inject badge';
}

