() => {
  // Get the full content of the insiders tab
  const body = document.querySelector('#company-profile-body') || document.querySelector('.company-profile-body');
  if (!body) return 'no body found';

  // Get all the table data
  const table = body.querySelector('table');
  const rows = table ? Array.from(table.querySelectorAll('tr')) : [];

  // Get headers
  const headers = rows.length > 0 ? Array.from(rows[0].querySelectorAll('th')).map(th => th.textContent.trim()) : [];

  // Get all data rows with computed styles
  const dataRows = rows.slice(1).map(tr => {
    const cells = Array.from(tr.querySelectorAll('td')).map(td => td.textContent.trim());
    const bgColor = window.getComputedStyle(tr).backgroundColor;
    const classes = tr.className;
    return { cells, bgColor, classes };
  });

  // Get everything before the table (sentiment indicator)
  const sentimentSection = body.querySelector('.insider-sentiment, .sentiment-indicator, .net-sentiment');
  const sentimentHTML = sentimentSection ? sentimentSection.innerHTML.substring(0, 500) : null;
  const sentimentText = sentimentSection ? sentimentSection.textContent.trim() : null;

  // Get everything after the table (source attribution)  
  const allText = body.textContent;
  const sourceMatch = allText.match(/Source:.*/);

  return {
    headers,
    rowCount: dataRows.length,
    rows: dataRows,
    sentimentText,
    sourceAttribution: sourceMatch ? sourceMatch[0] : null,
    fullText: allText.substring(allText.length - 200)
  };
}

() => {
  const body = document.querySelector('#company-profile-body');
  if (!body) return 'no body found';

  // Get the sentiment section - try various selectors
  const allDivs = body.querySelectorAll('div');
  let sentimentDiv = null;
  for (const div of allDivs) {
    if (div.textContent.includes('NET') && div.textContent.includes('SELL')) {
      sentimentDiv = div;
      break;
    }
  }

  if (!sentimentDiv) return { found: false, bodyHTML: body.innerHTML.substring(0, 1000) };

  return {
    found: true,
    text: sentimentDiv.textContent.trim().substring(0, 300),
    classes: sentimentDiv.className,
    borderLeftColor: window.getComputedStyle(sentimentDiv).borderLeftColor,
    borderLeftWidth: window.getComputedStyle(sentimentDiv).borderLeftWidth,
    innerHTML: sentimentDiv.innerHTML.substring(0, 500)
  };
}

