() => {
  // Try scrolling different elements within the modal
  const modal = document.getElementById('company-profile-modal');
  const body = document.getElementById('company-profile-body');
  const tableWrap = document.querySelector('.cp-insider-table-wrap');

  const results = {};

  if (modal) {
    results.modalScrollHeight = modal.scrollHeight;
    results.modalClientHeight = modal.clientHeight;
    results.modalOverflow = window.getComputedStyle(modal).overflow;
    modal.scrollTop = modal.scrollHeight;
  }

  if (body) {
    results.bodyScrollHeight = body.scrollHeight;
    results.bodyClientHeight = body.clientHeight;
    results.bodyOverflow = window.getComputedStyle(body).overflow;
    body.scrollTop = body.scrollHeight;
  }

  if (tableWrap) {
    results.tableWrapScrollHeight = tableWrap.scrollHeight;
    results.tableWrapClientHeight = tableWrap.clientHeight;
    results.tableWrapOverflow = window.getComputedStyle(tableWrap).overflow;
  }

  // Check if source attribution is in the viewport
  const source = document.querySelector('.cp-insider-source, .cp-source');
  if (!source) {
    // Try finding by text
    const allElements = document.querySelectorAll('p, div, span, footer');
    for (const el of allElements) {
      if (el.textContent.includes('Source: SEC EDGAR Form 4')) {
        results.sourceElement = {
          tag: el.tagName,
          class: el.className,
          rect: el.getBoundingClientRect()
        };
        el.scrollIntoView();
        break;
      }
    }
  } else {
    results.sourceElement = { tag: source.tagName, class: source.className };
    source.scrollIntoView();
  }

  return results;
}

